import { readFile, writeFile } from 'node:fs/promises';
import { resolve } from 'node:path';

const GENERATED_HEADER = [
	'// Generated by wasm-pack. Do not edit by hand.',
	'// Regenerate with: npm run build:wasm',
	'',
].join('\n');

const SELF_TYPES_RE = /^\/\* @ts-self-types=.*?\*\/\n/u;
const GENERATED_HEADER_RE =
	/^(?:\/\* @ts-self-types=.*?\*\/\n)?\/\/ Generated by wasm-pack\. Do not edit by hand\.\n\/\/ Regenerate with: npm run build:wasm\n\n/u;

const generatedTextFiles = [
	'src/ts/wasm/tachyon_ipc.js',
	'src/ts/wasm/tachyon_ipc_bg.js',
	'src/ts/wasm/tachyon_ipc.d.ts',
	'src/ts/wasm/tachyon_ipc_bg.wasm.d.ts',
];

for (const relativePath of generatedTextFiles) {
	const filePath = resolve(relativePath);
	let body = await readFile(filePath, 'utf8');
	body = body.replace(GENERATED_HEADER_RE, (match) => {
		const selfTypes = match.match(SELF_TYPES_RE)?.[0] ?? '';
		return selfTypes;
	});

	const selfTypes = body.match(SELF_TYPES_RE)?.[0] ?? '';
	if (selfTypes !== '') {
		body = body.slice(selfTypes.length);
	}

	await writeFile(filePath, `${selfTypes}${GENERATED_HEADER}${body}`);
}
